/**
 * MedX validator forms runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Field and cross-field validation rules.
 */
const VALIDATOR_TOKENS = Object.freeze({
  primary: { value: "forms-validator-primary", scope: "forms" },
  secondary: { value: "forms-validator-secondary", scope: "forms" },
  muted: { value: "forms-validator-muted", scope: "forms" },
  accent: { value: "forms-validator-accent", scope: "forms" },
  surface: { value: "forms-validator-surface", scope: "forms" },
});

const VALIDATOR_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const VALIDATOR_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const validatorRegistry = new Map();
const VALIDATOR_listeners = new Set();
let VALIDATOR_seq = 0;

function createValidatorId(prefix = "medx-forms-validator") {
  VALIDATOR_seq += 1;
  return `${prefix}-${VALIDATOR_seq}`;
}

function registerValidator(config = {}) {
  const entryId = config.id ?? createValidatorId();
  const preset = VALIDATOR_PRESETS[config.preset ?? "default"] ?? VALIDATOR_PRESETS.default;
  const token = VALIDATOR_TOKENS[config.token ?? preset.token] ?? VALIDATOR_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: VALIDATOR_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  validatorRegistry.set(entryId, entry);
  notifyValidatorListeners("register", entry);
  return entry;
}

function updateValidator(id, patch = {}) {
  const entry = validatorRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyValidatorListeners("update", entry);
  return entry;
}

function resolveValidator(id) {
  const entry = validatorRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listValidatorEntries(filter = {}) {
  let items = Array.from(validatorRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onValidatorEvent(listener) {
  VALIDATOR_listeners.add(listener);
  return () => VALIDATOR_listeners.delete(listener);
}

function notifyValidatorListeners(type, entry) {
  for (const listener of VALIDATOR_listeners) {
    try {
      listener({ type, entry, registrySize: validatorRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:forms:validator] listener error", err.message);
    }
  }
}

function getValidatorMetrics() {
  const items = listValidatorEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(VALIDATOR_TOKENS).length,
    presets: Object.keys(VALIDATOR_PRESETS).length,
  };
}

async function runMedxValidator() {
  console.log("[medx:ui:forms:validator] runtime initialized");
  console.log(`[medx:ui:forms:validator] tokens=${Object.keys(VALIDATOR_TOKENS).length} presets=${Object.keys(VALIDATOR_PRESETS).length}`);

  const events = [];
  onValidatorEvent((e) => events.push(e.type));

  const domains = Object.keys(VALIDATOR_SUPPLY_CHAIN);
  const presets = Object.keys(VALIDATOR_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerValidator({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "forms/validator" },
    });
  }

  const first = listValidatorEntries()[0];
  if (first) updateValidator(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getValidatorMetrics();
  const resolved = first ? resolveValidator(first.id) : null;

  console.log(`[medx:ui:forms:validator] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:forms:validator] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:forms:validator] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:forms:validator] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:forms:validator] bootstrap complete");
}

module.exports = runMedxValidator;
